	sort.Slice(edgeList, func(i, j int) bool {
		return edgeList[i][2] < edgeList[j][2]
	})

	uf := NewUnionFind(int(n))
	components := int(n)
	var maxCost int64 = 0

	for _, edge := range edgeList {
